/**
 * StockMarket Component
 *
 * Public page displaying live stock cards for the top 20 tickers.
 *
 * Key behaviours:
 * - Fetches stock metadata from own backend DB on mount
 * - Fetches all live quotes from backend (which proxies Polygon) in one call
 * - Polls for fresh quotes every 60 seconds
 * - Countdown timer shows seconds until next refresh
 * - Filter by sector and exchange
 * - Search by name or symbol
 * - Green / red color coding for price movement
 * - Accessible to all visitors (no auth required)
 */

import { useEffect, useState, useCallback } from "react";
import Header from "../components/Header";

const POLL_INTERVAL = 60 * 1000; // 60 seconds

function StockMarket() {
  const [stocks, setStocks] = useState([]);         // DB metadata
  const [quotes, setQuotes] = useState({});         // live prices keyed by symbol
  const [loadingStocks, setLoadingStocks] = useState(true);
  const [loadingQuotes, setLoadingQuotes] = useState(true);
  const [error, setError] = useState(null);
  const [lastUpdated, setLastUpdated] = useState(null);
  const [countdown, setCountdown] = useState(POLL_INTERVAL / 1000);
  const [searchTerm, setSearchTerm] = useState("");
  const [sectorFilter, setSectorFilter] = useState("All");
  const [exchangeFilter, setExchangeFilter] = useState("All");

  // Fetch static stock metadata from our DB once
  useEffect(() => {
    fetch("http://localhost:5000/api/stocks")
      .then((res) => {
        if (!res.ok) throw new Error("Failed to load stocks");
        return res.json();
      })
      .then((data) => {
        setStocks(data);
        setLoadingStocks(false);
      })
      .catch((err) => {
        setError(err.message);
        setLoadingStocks(false);
      });
  }, []);

  // Fetch all live quotes from backend (proxied to Polygon)
  const fetchQuotes = useCallback(async () => {
    try {
      setError(null);
      const res = await fetch("http://localhost:5000/api/stocks/quotes/all");
      if (!res.ok) throw new Error("Failed to load quotes");
      const data = await res.json();

      // Key quotes by symbol for O(1) lookup
      const quotesMap = {};
      data.forEach((q) => {
        quotesMap[q.symbol] = q;
      });

      setQuotes(quotesMap);
      setLastUpdated(new Date());
      setCountdown(POLL_INTERVAL / 1000);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoadingQuotes(false);
    }
  }, []);

  // Initial fetch + polling interval
  useEffect(() => {
    fetchQuotes();
    const interval = setInterval(fetchQuotes, POLL_INTERVAL);
    return () => clearInterval(interval);
  }, [fetchQuotes]);

  // Countdown ticker
  useEffect(() => {
    const tick = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);
    return () => clearInterval(tick);
  }, []);

  // Derive unique sectors for filter dropdown
  const sectors = ["All", ...Array.from(new Set(stocks.map((s) => s.sector))).sort()];
  const exchanges = ["All", "NASDAQ", "NYSE"];

  // Apply filters + search
  const filtered = stocks.filter((s) => {
    const matchesSearch =
      s.symbol.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSector = sectorFilter === "All" || s.sector === sectorFilter;
    const matchesExchange = exchangeFilter === "All" || s.exchange === exchangeFilter;
    return matchesSearch && matchesSector && matchesExchange;
  });

  function formatPrice(price) {
    if (price === null || price === undefined) return "—";
    return "$" + (price >= 1000
      ? price.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })
      : price.toFixed(2));
  }

  function formatChange(change) {
    if (change === null || change === undefined) return "—";
    const sign = change >= 0 ? "+" : "";
    return `${sign}${change.toFixed(2)}`;
  }

  function formatChangePct(pct) {
    if (pct === null || pct === undefined) return "—";
    const sign = pct >= 0 ? "+" : "";
    return `${sign}${pct.toFixed(2)}%`;
  }

  function formatVolume(vol) {
    if (!vol) return "—";
    if (vol >= 1_000_000) return (vol / 1_000_000).toFixed(1) + "M";
    if (vol >= 1_000) return (vol / 1_000).toFixed(0) + "K";
    return vol.toString();
  }

  const isLoading = loadingStocks || loadingQuotes;

  return (
    <div style={styles.page}>
      <style>{googleFonts}</style>
      <Header />

      <main style={styles.main}>

        {/* Page Header */}
        <header style={styles.pageHeader}>
          <div>
            <h1 style={styles.title}>Stock Market</h1>
            <p style={styles.subtitle}>Top 20 by market cap · Previous day's close</p>
          </div>

          {/* Refresh status */}
          <div style={styles.refreshInfo}>
            {lastUpdated && (
              <span style={styles.lastUpdated}>
                Updated {lastUpdated.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
              </span>
            )}
            <div style={styles.countdownBadge}>
              <span style={styles.countdownDot} />
              Refreshing in {countdown}s
            </div>
            <button style={styles.refreshBtn} onClick={fetchQuotes} title="Refresh now">
              ↻
            </button>
          </div>
        </header>

        {/* Filters */}
        <div style={styles.filtersRow}>
          {/* Search */}
          <div style={styles.searchWrap}>
            <svg style={styles.searchIcon} width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#666" strokeWidth="2">
              <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            <input
              type="text"
              placeholder="Search symbol or name…"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={styles.searchInput}
            />
          </div>

          {/* Sector filter */}
          <select
            value={sectorFilter}
            onChange={(e) => setSectorFilter(e.target.value)}
            style={styles.select}
          >
            {sectors.map((s) => <option key={s} value={s}>{s === "All" ? "All Sectors" : s}</option>)}
          </select>

          {/* Exchange filter */}
          <select
            value={exchangeFilter}
            onChange={(e) => setExchangeFilter(e.target.value)}
            style={styles.select}
          >
            {exchanges.map((e) => <option key={e} value={e}>{e === "All" ? "All Exchanges" : e}</option>)}
          </select>

          <span style={styles.resultCount}>{filtered.length} stocks</span>
        </div>

        {/* Error */}
        {error && (
          <div style={styles.errorBanner} role="alert">
            ⚠ {error} — <button style={styles.retryBtn} onClick={fetchQuotes}>Retry</button>
          </div>
        )}

        {/* Loading skeleton */}
        {isLoading ? (
          <div style={styles.grid}>
            {Array.from({ length: 20 }).map((_, i) => (
              <div key={i} style={styles.skeleton} />
            ))}
          </div>
        ) : (
          <div style={styles.grid}>
            {filtered.map((stock) => {
              const q = quotes[stock.symbol];
              const isPositive = q?.change >= 0;
              const isNegative = q?.change < 0;
              const changeColor = isPositive ? "#00C076" : isNegative ? "#FF4D4D" : "#888";
              const changeBg = isPositive ? "rgba(0,192,118,0.08)" : isNegative ? "rgba(255,77,77,0.08)" : "transparent";

              return (
                <article key={stock.symbol} style={styles.card}>

                  {/* Card top row — symbol + exchange badge */}
                  <div style={styles.cardTop}>
                    <div>
                      <span style={styles.symbol}>{stock.symbol}</span>
                      <span style={styles.exchangeBadge}>{stock.exchange}</span>
                    </div>
                    <span style={{ ...styles.sectorTag }}>
                      {stock.sector}
                    </span>
                  </div>

                  {/* Company name */}
                  <p style={styles.companyName}>{stock.name}</p>

                  {/* Price */}
                  <div style={styles.priceRow}>
                    <span style={styles.price}>
                      {q ? formatPrice(q.price) : <span style={styles.loadingDash}>—</span>}
                    </span>
                  </div>

                  {/* Change + Change % */}
                  <div style={{ ...styles.changeRow, backgroundColor: changeBg, borderColor: changeColor + "33" }}>
                    <span style={{ ...styles.change, color: changeColor }}>
                      {q ? formatChange(q.change) : "—"}
                    </span>
                    <span style={{ ...styles.changePct, color: changeColor }}>
                      {q ? formatChangePct(q.changePct) : "—"}
                    </span>
                  </div>

                  {/* Volume */}
                  <div style={styles.volumeRow}>
                    <span style={styles.volumeLabel}>Vol</span>
                    <span style={styles.volumeValue}>{q ? formatVolume(q.volume) : "—"}</span>
                  </div>

                </article>
              );
            })}
          </div>
        )}

      </main>
    </div>
  );
}

